#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void measure_dram_latency(volatile uint64_t* indices, uint64_t* cycles_out, size_t array_size, uint64_t num_iterations) {
    // Single thread execution for accurate latency measurement
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint64_t idx = 0;

    // Compiler barrier before timing
    asm volatile("" : : : "memory");

    // Warm-up pass (1 iteration)
    idx = indices[idx];

    __threadfence();

    // Start timing
    volatile uint64_t start = clock64();

    #pragma unroll 1
    for (uint64_t i = 0; i < num_iterations; i++) {
        idx = indices[idx];  // Serial dependency chain
    }

    // End timing
    volatile uint64_t end = clock64();

    // Compiler barrier after timing
    asm volatile("" : : : "memory");

    // Anti-optimization sink (cast to uint64_t first!)
    volatile uint64_t sink64 = idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    // Calculate average cycles per access
    uint64_t avg_cycles = (end - start) / num_iterations;
    *cycles_out = avg_cycles;
}

int main() {
    const size_t array_size = 32 * 1024 * 1024;  // 32M elements = 256 MB (128 bytes per element stride)
    const uint64_t num_iterations = 1000000;      // 1 million pointer hops per trial
    const int num_trials = 3;
    uint64_t* cycles_host = (uint64_t*)malloc(num_trials * sizeof(uint64_t));
    uint64_t* cycles_dev;
    uint64_t* indices_dev;

    // Allocate device memory
    cudaMalloc(&indices_dev, array_size * sizeof(uint64_t));
    cudaMalloc(&cycles_dev, sizeof(uint64_t));

    // Create host array with pointer-chasing pattern
    uint64_t* indices_host = (uint64_t*)malloc(array_size * sizeof(uint64_t));

    // Initialize with sequential stride pattern (128 bytes = 16 * 8 bytes)
    const uint64_t stride = 16;  // 128-byte cache line stride
    for (size_t i = 0; i < array_size - stride; i++) {
        indices_host[i] = (i + stride) % array_size;
    }
    indices_host[array_size - 1] = 0;  // Wrap around

    // Copy to device
    cudaMemcpy(indices_dev, indices_host, array_size * sizeof(uint64_t), cudaMemcpyHostToDevice);

    // Run trials
    for (int trial = 0; trial < num_trials; trial++) {
        // Launch kernel
        measure_dram_latency<<<1, 1>>>(indices_dev, cycles_dev, array_size, num_iterations);
        cudaDeviceSynchronize();

        // Copy result back
        cudaMemcpy(&cycles_host[trial], cycles_dev, sizeof(uint64_t), cudaMemcpyDeviceToHost);
    }

    // Sort results to get median
    std::sort(cycles_host, cycles_host + num_trials);
    uint64_t median_cycles = cycles_host[num_trials / 2];

    printf("dram_latency_cycles: %lu\n", median_cycles);

    // Cleanup
    free(cycles_host);
    free(indices_host);
    cudaFree(cycles_dev);
    cudaFree(indices_dev);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void cache_benchmark(volatile float* data, size_t array_size_floats, uint32_t passes, float* time_ms) {
    if (threadIdx.x >= 256) return;

    uint32_t idx = threadIdx.x;
    uint32_t stride = blockDim.x;

    volatile float sink = 0.0f;

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);

    #pragma unroll 1
    for (uint32_t p = 0; p < passes; p++) {
        for (size_t i = 0; i < array_size_floats / 256; i++) {
            idx = (idx + stride) % array_size_floats;
            sink += data[idx];
        }
    }

    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    cudaEventElapsedTime(time_ms, start, stop);

    data[threadIdx.x] = sink;
}

int main() {
    const size_t sizes_mb[] = {1, 2, 4, 8, 16, 32, 64, 128};
    const uint32_t passes = 10;
    const uint32_t num_trials = 3;

    float* d_data;
    float* d_time;

    float bandwidths[8];

    for (int i = 0; i < 8; i++) {
        size_t size_mb = sizes_mb[i];
        size_t array_size_floats = (size_t)(size_mb) * 1024 * 1024 / sizeof(float);

        cudaMalloc(&d_data, array_size_floats * sizeof(float));
        cudaMalloc(&d_time, sizeof(float));

        for (uint32_t trial = 0; trial < num_trials; trial++) {
            cudaMemset(d_data, 0, array_size_floats * sizeof(float));

            float h_time_ms = 0.0f;
            cache_benchmark<<<1, 256>>>(d_data, array_size_floats, passes, d_time);
            cudaMemcpy(&h_time_ms, d_time, sizeof(float), cudaMemcpyDeviceToHost);

            double bytes_processed = (double)array_size_floats * sizeof(float) * passes;
            double bandwidth_gbps = bytes_processed / (h_time_ms / 1000.0) / 1e9;

            bandwidths[i] += bandwidth_gbps;
        }

        bandwidths[i] /= num_trials;

        cudaFree(d_data);
        cudaFree(d_time);
    }

    float max_bandwidth = 0.0f;
    for (int i = 0; i < 8; i++) {
        if (bandwidths[i] > max_bandwidth) max_bandwidth = bandwidths[i];
    }

    float threshold = max_bandwidth * 0.9f;
    int cache_size_mb = 1;
    for (int i = 0; i < 8; i++) {
        if (bandwidths[i] > threshold) {
            cache_size_mb = sizes_mb[i];
        } else {
            break;
        }
    }

    printf("l2_cache_size_mb: %d\n", cache_size_mb);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>
#include <vector>

__global__ void cache_benchmark_kernel(volatile float* data, size_t size, int passes) {
    int tid = threadIdx.x + blockIdx.x * blockDim.x;
    int stride = blockDim.x * gridDim.x;

    // Each thread accesses its portion of the array
    for (int p = 0; p < passes; p++) {
        for (size_t i = tid; i < size / sizeof(float); i += stride) {
            data[i] = data[i] + 1.0f;  // Read and write
        }
    }
}

int main() {
    const size_t sizes_mb[] = {1, 2, 4, 8, 16, 32, 64, 128};
    const int num_sizes = sizeof(sizes_mb) / sizeof(sizes_mb[0]);
    const int passes = 10;
    const int threads = 256;
    const int blocks = 128;

    std::vector<float> bandwidths(num_sizes);

    for (int i = 0; i < num_sizes; i++) {
        size_t size = sizes_mb[i] * 1024 * 1024;
        volatile float* d_data;
        cudaMalloc(&d_data, size);

        // Warmup
        cache_benchmark_kernel<<<blocks, threads>>>(d_data, size, 1);
        cudaDeviceSynchronize();

        // Create events for timing
        cudaEvent_t start, stop;
        cudaEventCreate(&start);
        cudaEventCreate(&stop);

        // Time the kernel
        cudaEventRecord(start);
        cache_benchmark_kernel<<<blocks, threads>>>(d_data, size, passes);
        cudaEventRecord(stop);
        cudaEventSynchronize(stop);

        float elapsed_ms = 0;
        cudaEventElapsedTime(&elapsed_ms, start, stop);

        // Calculate bandwidth in GB/s
        float bytes_processed = (float)size * passes;
        float elapsed_seconds = elapsed_ms / 1000.0f;
        bandwidths[i] = (bytes_processed / (1024.0f * 1024.0f * 1024.0f)) / elapsed_seconds;

        cudaFree((void*)d_data);
        cudaEventDestroy(start);
        cudaEventDestroy(stop);
    }

    // Find L2 cache size - look for the largest size before significant bandwidth drop
    float baseline_bw = bandwidths[0];
    int l2_size_mb = 8; // default

    for (int i = 1; i < num_sizes; i++) {
        float drop_percentage = (baseline_bw - bandwidths[i]) / baseline_bw * 100.0f;
        if (drop_percentage > 10.0f && i > 1) {
            l2_size_mb = sizes_mb[i-1];
            break;
        }
    }

    printf("l2_cache_size_mb: %d\n", l2_size_mb);
    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void cache_benchmark(float* data, size_t array_size_elements, uint64_t* access_cycles) {
    if (threadIdx.x >= 256) return;

    const int passes = 10;
    const size_t stride = 1;

    // Warmup pass
    for (int pass = 0; pass < 1; pass++) {
        size_t idx = threadIdx.x;
        while (idx < array_size_elements) {
            volatile float val = data[idx];
            idx += gridDim.x * blockDim.x * stride;
        }
    }

    __threadfence();

    // Timed passes
    volatile uint64_t start = clock64();
    for (int pass = 0; pass < passes; pass++) {
        size_t idx = threadIdx.x;
        while (idx < array_size_elements) {
            volatile float val = data[idx];
            idx += gridDim.x * blockDim.x * stride;
        }
    }
    volatile uint64_t end = clock64();

    if (threadIdx.x == 0) {
        *access_cycles = (end - start) / passes;
    }
}

int main() {
    float* d_data;
    uint64_t* d_cycles;

    // Test sizes: 1MB to 128MB
    size_t sizes[] = {262144, 524288, 1048576, 2097152, 4194304, 8388608, 16777216, 33554432};
    const int num_sizes = 8;

    float bandwidths[8];

    for (int i = 0; i < num_sizes; i++) {
        size_t array_size = sizes[i];
        size_t array_bytes = array_size * sizeof(float);

        cudaMalloc(&d_data, array_bytes);
        cudaMalloc(&d_cycles, sizeof(uint64_t));

        // Initialize data
        float* h_data = (float*)malloc(array_bytes);
        for (size_t j = 0; j < array_size; j++) {
            h_data[j] = 1.0f;
        }
        cudaMemcpy(d_data, h_data, array_bytes, cudaMemcpyHostToDevice);
        free(h_data);

        // Launch kernel
        dim3 grid(1);
        dim3 block(256);
        cache_benchmark<<<grid, block>>>(d_data, array_size, d_cycles);
        cudaDeviceSynchronize();

        // Get cycles
        uint64_t cycles;
        cudaMemcpy(&cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);

        // Calculate bandwidth in GB/s
        float bytes_accessed = array_bytes * 10.0f; // 10 passes
        float seconds = cycles / 1.41e9f; // Assuming 1.41 GHz base clock
        bandwidths[i] = (bytes_accessed / (1024.0f * 1024.0f * 1024.0f)) / seconds;

        cudaFree(d_data);
        cudaFree(d_cycles);
    }

    // Find L2 cache size (knee point)
    int knee_index = 0;
    float max_bandwidth = bandwidths[0];
    for (int i = 0; i < num_sizes; i++) {
        if (bandwidths[i] > max_bandwidth) {
            max_bandwidth = bandwidths[i];
        }
    }

    for (int i = 1; i < num_sizes; i++) {
        if (bandwidths[i] < max_bandwidth * 0.9f) { // 10% drop
            knee_index = i - 1;
            break;
        }
    }

    // Convert to MB
    float l2_size_mb = (sizes[knee_index] * sizeof(float)) / (1024.0f * 1024.0f);

    printf("l2_cache_size_mb: %.1f\n", l2_size_mb);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

#define NUM_SIZES 8
#define NUM_TRIALS 3
#define NUM_THREADS 256
#define PASSES 10

__global__ void cache_benchmark(float* data, size_t array_size) {
    size_t idx = threadIdx.x + blockIdx.x * blockDim.x;
    size_t stride = blockDim.x * gridDim.x;

    // Each thread processes elements with stride
    for (size_t pass = 0; pass < PASSES; pass++) {
        for (size_t i = idx; i < array_size; i += stride) {
            // Read-modify-write to prevent optimization
            float val = data[i];
            data[i] = val + 1.0f;
        }
        __syncthreads();
    }
}

int main() {
    // Array sizes: 1, 2, 4, 8, 16, 32, 64, 128 MB
    size_t sizes[NUM_SIZES] = {1, 2, 4, 8, 16, 32, 64, 128};
    float bandwidths[NUM_SIZES];

    float* d_data;
    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    for (int i = 0; i < NUM_SIZES; i++) {
        size_t array_size = (sizes[i] * 1024 * 1024) / sizeof(float);
        size_t mem_size = array_size * sizeof(float);

        cudaMalloc(&d_data, mem_size);

        // Initialize data
        float* h_data = (float*)malloc(mem_size);
        for (size_t j = 0; j < array_size; j++) {
            h_data[j] = 1.0f;
        }
        cudaMemcpy(d_data, h_data, mem_size, cudaMemcpyHostToDevice);
        free(h_data);

        float trial_times[NUM_TRIALS];
        for (int trial = 0; trial < NUM_TRIALS; trial++) {
            // Warmup
            cache_benchmark<<<1, NUM_THREADS>>>(d_data, array_size);
            cudaDeviceSynchronize();

            // Timed run
            cudaEventRecord(start);
            cache_benchmark<<<1, NUM_THREADS>>>(d_data, array_size);
            cudaEventRecord(stop);
            cudaEventSynchronize(stop);

            float milliseconds = 0;
            cudaEventElapsedTime(&milliseconds, start, stop);
            trial_times[trial] = milliseconds / 1000.0f; // Convert to seconds
        }

        // Calculate median time
        std::sort(trial_times, trial_times + NUM_TRIALS);
        float median_time = trial_times[NUM_TRIALS / 2];

        // Calculate bandwidth in GB/s
        // Total bytes transferred = array_size * sizeof(float) * PASSES * 2 (read+write)
        float total_bytes = array_size * sizeof(float) * PASSES * 2.0f;
        float bandwidth = (total_bytes / median_time) / (1024 * 1024 * 1024); // GB/s
        bandwidths[i] = bandwidth;

        cudaFree(d_data);
    }

    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    // Find L2 cache size by detecting bandwidth cliff
    // Look for the largest size before >10% bandwidth drop
    float max_bandwidth = bandwidths[0];
    float threshold = max_bandwidth * 0.9f; // 10% drop threshold
    size_t l2_cache_mb = sizes[0];

    for (int i = 1; i < NUM_SIZES; i++) {
        if (bandwidths[i] < threshold) {
            // Found cliff - L2 cache is previous size
            l2_cache_mb = sizes[i-1];
            break;
        }
        // If no cliff found, use the last size that still has good bandwidth
        l2_cache_mb = sizes[i];
    }

    printf("l2_cache_size_mb: %lu\n", l2_cache_mb);

    return 0;
}
